sql:
SELECT cause_name
FROM causes_of_death
WHERE category = 'Respiratory';

external_knowledge:
; CLRD stands for Chronic Lower Respiratory Diseases, which include conditions such as chronic bronchitis and emphysema; 
; Air quality index is a measure of the level of air pollution in a given area, with higher values indicating poorer air quality; 
; Air-related health interventions refer to public health programs or initiatives aimed at reducing the negative impacts of air pollution on human health.
